// server/middleware/isAdmin.ts
var import_jsonwebtoken2 = __toESM(require_jsonwebtoken(), 1);
var import_client2 = __toESM(require_default2(), 1);
var prisma2 = new import_client2.PrismaClient;
async function isAdmin(req, res, next) {
  try {
    const authHeader = req.headers.authorization;
    if (!authHeader) {
      return res.status(401).json({ message: "No authorization token provided" });
    }
    const token2 = authHeader.split(" ")[1];
    if (!token2) {
      return res.status(401).json({ message: "No token provided" });
    }
    const JWT_SECRET2 = process.env.JWT_SECRET || "guardian-jwt-secret-key";
    const decoded = import_jsonwebtoken2.default.verify(token2, JWT_SECRET2);
    const userRoles = await prisma2.uSER_ROLES.findMany({
      where: { USER_ID: decoded.id },
      select: { ROLE_ID: true }
    });
    const roleIds = userRoles.map((ur3) => ur3.ROLE_ID);
    const hasAdminAccess = roleIds.includes(1) || roleIds.includes(6);
    if (!hasAdminAccess) {
      return res.status(403).json({
        message: "Forbidden: Admin or JAFAR access required.",
        debug: {
          userId: decoded.id,
          roles: roleIds,
          hasAdmin: roleIds.includes(1),
          hasJafar: roleIds.includes(6)
        }
      });
    }
    req.user = {
      id: decoded.id,
      email: decoded.email,
      role: roleIds.includes(1) ? "1" : "6",
      COMPANY_ID: decoded.COMPANY_ID
    };
    next();
  } catch (error) {
    console.error("Error in isAdmin middleware:", error);
    const errorMessage = error instanceof Error ? error.message : "Unknown error";
    return res.status(401).json({
      message: "Invalid or expired token",
      error: errorMessage
    });
  }
}

