// server/middleware/isExternalUser.ts
function isExternalUser(req, res, next) {
  const role = req.user?.role || "";
  if (role === "5" || role === "6") {
    return next();
  }
  return res.status(403).json({ message: "Forbidden: External users only." });
}
function allowExternalUser(req, res, next) {
  const role = req.user?.role || "";
  req.isExternal = role === "5";
  req.isJafarDeveloper = role === "6";
  return next();
}
function filterExternalUserData(req, res, next) {
  const role = req.user?.role || "";
  const userId = req.user?.id;
  if (role === "6") {
    next();
    return;
  }
  if (role === "5" && userId) {
    req.externalUserFilter = {
      userId,
      externalOnly: true
    };
  }
  next();
}

