var router3 = import_express3.default.Router();
function extractRoutes(app) {
  const routes = [];
  const stack = app._router.stack;
  stack.forEach((layer) => {
    if (layer.route) {
      const path2 = layer.route.path;
      const methods = Object.keys(layer.route.methods).filter((method) => layer.route.methods[method]).map((method) => method.toUpperCase());
      routes.push({
        path: path2,
        methods,
        type: "route"
      });
    } else if (layer.name === "router" && layer.handle.stack) {
      let routerPath = "/";
      if (layer.regexp) {
        const regexpStr = layer.regexp.toString();
        const match = regexpStr.match(/^\/?\^(\\\/[^\?]+)\?/i);
        if (match) {
          routerPath = match[1].replace(/\\\//g, "/");
        }
      }
      layer.handle.stack.forEach((routerLayer) => {
        if (routerLayer.route) {
          const subPath = routerLayer.route.path;
          const fullPath = routerPath + (subPath === "/" ? "" : subPath);
          const methods = Object.keys(routerLayer.route.methods).filter((method) => routerLayer.route.methods[method]).map((method) => method.toUpperCase());
          routes.push({
            path: fullPath,
            methods,
            type: "router"
          });
        }
      });
    }
  });
  return routes;
}
router3.get("/", (req, res) => {
  const app = req.app;
  const routes = extractRoutes(app);
  const groupedRoutes = {};
  routes.forEach((route) => {
    const basePath = route.path.split("/")[1] || "root";
    if (!groupedRoutes[basePath]) {
      groupedRoutes[basePath] = [];
    }
    groupedRoutes[basePath].push(route);
  });
  res.json({
    totalEndpoints: routes.length,
    groups: groupedRoutes,
    routes: routes.sort((a, b3) => a.path.localeCompare(b3.path))
  });
});
